"""
Represents the Checkers board.
"""

class Board:
    def __init__(self):
        self.board = self._create_board()

    def _create_board(self):
        # Initialize an 8x8 board with pieces in the starting positions
        board = [[' ' for _ in range(8)] for _ in range(8)]
        for row in range(3):
            for col in range((row + 1) % 2, 8, 2):
                board[row][col] = 'W'
        for row in range(5, 8):
            for col in range((row - 4) % 2, 8, 2):
                board[row][col] = 'B'
        return board

    def display(self):
        for row in self.board:
            print(' '.join(row))
