    def make_move(self, from_pos: Tuple[int, int], to_pos: Tuple[int, int]) -> bool:
        piece = self.state[from_pos[0]][from_pos[1]]
        if piece is None or piece.lower() == 'k':  # No move for kings
            return False
        dx, dy = to_pos[0] - from_pos[0], to_pos[1] - from_pos[1]
        if abs(dx) != abs(dy) or dx == 0:
            return False
        if self.state[to_pos[0]][to_pos[1]] is not None:
            return False
        # Check for jumps and captures
        if abs(dx) == 2 and abs(dy) == 2:
            middle_piece = (from_pos[0] + dx // 2, from_pos[1] + dy // 2)
            if self.state[middle_piece[0]][middle_piece[1]] is None or self.state[middle_piece[0]][middle_piece[1]].lower() == piece.lower():
                return False
        # Move the piece
        self.state[to_pos[0]][to_pos[1]] = piece
        self.state[from_pos[0]][from_pos[1]] = None
        return True

    def check_winner(self) -> str:
        black_pieces, white_pieces = 0, 0
        for row in self.state:
